11475 ScalarEvolution::getLoopInvariantExitCondDuringFirstIterationsImpl(
11476     CmpPredicate Pred, const SCEV *LHS, const SCEV *RHS, const Loop *L,
11477     const Instruction *CtxI, const SCEV *MaxIter) {
11478   // Try to prove the following set of facts:
11479   // - The predicate is monotonic in the iteration space.
11480   // - If the check does not fail on the 1st iteration:
11481   //   - No overflow will happen during first MaxIter iterations;
11482   //   - It will not fail on the MaxIter'th iteration.
11483   // If the check does fail on the 1st iteration, we leave the loop and no
11484   // other checks matter.
11485 
11486   // If there is a loop-invariant, force it into the RHS, otherwise bail out.
11487   if (!isLoopInvariant(RHS, L)) {
11488     if (!isLoopInvariant(LHS, L))
11489       return std::nullopt;
11490 
11491     std::swap(LHS, RHS);
11492     Pred = ICmpInst::getSwappedCmpPredicate(Pred);
11493   }
11494 
11495   auto *AR = dyn_cast<SCEVAddRecExpr>(LHS);
11496   if (!AR || AR->getLoop() != L)
11497     return std::nullopt;
11498 
11499   // Even if both are valid, we need to consistently chose the unsigned or the
11500   // signed predicate below, not mixtures of both. For now, prefer the unsigned
11501   // predicate.
11502   Pred = Pred.dropSameSign();
11503 
11504   // The predicate must be relational (i.e. <, <=, >=, >).
11505   if (!ICmpInst::isRelational(Pred))
11506     return std::nullopt;
11507 
11508   // TODO: Support steps other than +/- 1.
11509   const SCEV *Step = AR->getStepRecurrence(*this);
11510   auto *One = getOne(Step->getType());
11511   auto *MinusOne = getNegativeSCEV(One);
11512   if (Step != One && Step != MinusOne)
11513     return std::nullopt;
11514 
11515   // Type mismatch here means that MaxIter is potentially larger than max
11516   // unsigned value in start type, which mean we cannot prove no wrap for the
11517   // indvar.
11518   if (AR->getType() != MaxIter->getType())
11519     return std::nullopt;
11520 
11521   // Value of IV on suggested last iteration.
11522   const SCEV *Last = AR->evaluateAtIteration(MaxIter, *this);
11523   // Does it still meet the requirement?
11524   if (!isLoopBackedgeGuardedByCond(L, Pred, Last, RHS))
11525     return std::nullopt;
11526   // Because step is +/- 1 and MaxIter has same type as Start (i.e. it does
11527   // not exceed max unsigned value of this type), this effectively proves
11528   // that there is no wrap during the iteration. To prove that there is no
11529   // signed/unsigned wrap, we need to check that
11530   // Start <= Last for step = 1 or Start >= Last for step = -1.
11531   ICmpInst::Predicate NoOverflowPred =
11532       CmpInst::isSigned(Pred) ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
11533   if (Step == MinusOne)
11534     NoOverflowPred = ICmpInst::getSwappedPredicate(NoOverflowPred);
11535   const SCEV *Start = AR->getStart();
11536   if (!isKnownPredicateAt(NoOverflowPred, Start, Last, CtxI))
11537     return std::nullopt;
11538 
11539   // Everything is fine.
11540   return ScalarEvolution::LoopInvariantPredicate(Pred, Start, RHS);
11541 }
