11543 bool ScalarEvolution::isKnownPredicateViaConstantRanges(CmpPredicate Pred,
11544                                                         const SCEV *LHS,
11545                                                         const SCEV *RHS) {
11546   if (HasSameValue(LHS, RHS))
11547     return ICmpInst::isTrueWhenEqual(Pred);
11548 
11549   auto CheckRange = [&](bool IsSigned) {
11550     auto RangeLHS = IsSigned ? getSignedRange(LHS) : getUnsignedRange(LHS);
11551     auto RangeRHS = IsSigned ? getSignedRange(RHS) : getUnsignedRange(RHS);
11552     return RangeLHS.icmp(Pred, RangeRHS);
11553   };
11554 
11555   // The check at the top of the function catches the case where the values are
11556   // known to be equal.
11557   if (Pred == CmpInst::ICMP_EQ)
11558     return false;
11559 
11560   if (Pred == CmpInst::ICMP_NE) {
11561     if (CheckRange(true) || CheckRange(false))
11562       return true;
11563     auto *Diff = getMinusSCEV(LHS, RHS);
11564     return !isa<SCEVCouldNotCompute>(Diff) && isKnownNonZero(Diff);
11565   }
11566 
11567   return CheckRange(CmpInst::isSigned(Pred));
11568 }
