11570 bool ScalarEvolution::isKnownPredicateViaNoOverflow(CmpPredicate Pred,
11571                                                     const SCEV *LHS,
11572                                                     const SCEV *RHS) {
11573   // Match X to (A + C1)<ExpectedFlags> and Y to (A + C2)<ExpectedFlags>, where
11574   // C1 and C2 are constant integers. If either X or Y are not add expressions,
11575   // consider them as X + 0 and Y + 0 respectively. C1 and C2 are returned via
11576   // OutC1 and OutC2.
11577   auto MatchBinaryAddToConst = [this](const SCEV *X, const SCEV *Y,
11578                                       APInt &OutC1, APInt &OutC2,
11579                                       SCEV::NoWrapFlags ExpectedFlags) {
11580     const SCEV *XNonConstOp, *XConstOp;
11581     const SCEV *YNonConstOp, *YConstOp;
11582     SCEV::NoWrapFlags XFlagsPresent;
11583     SCEV::NoWrapFlags YFlagsPresent;
11584 
11585     if (!splitBinaryAdd(X, XConstOp, XNonConstOp, XFlagsPresent)) {
11586       XConstOp = getZero(X->getType());
11587       XNonConstOp = X;
11588       XFlagsPresent = ExpectedFlags;
11589     }
11590     if (!isa<SCEVConstant>(XConstOp))
11591       return false;
11592 
11593     if (!splitBinaryAdd(Y, YConstOp, YNonConstOp, YFlagsPresent)) {
11594       YConstOp = getZero(Y->getType());
11595       YNonConstOp = Y;
11596       YFlagsPresent = ExpectedFlags;
11597     }
11598 
11599     if (YNonConstOp != XNonConstOp)
11600       return false;
11601 
11602     if (!isa<SCEVConstant>(YConstOp))
11603       return false;
11604 
11605     // When matching ADDs with NUW flags (and unsigned predicates), only the
11606     // second ADD (with the larger constant) requires NUW.
11607     if ((YFlagsPresent & ExpectedFlags) != ExpectedFlags)
11608       return false;
11609     if (ExpectedFlags != SCEV::FlagNUW &&
11610         (XFlagsPresent & ExpectedFlags) != ExpectedFlags) {
11611       return false;
11612     }
11613 
11614     OutC1 = cast<SCEVConstant>(XConstOp)->getAPInt();
11615     OutC2 = cast<SCEVConstant>(YConstOp)->getAPInt();
11616 
11617     return true;
11618   };
11619 
11620   APInt C1;
11621   APInt C2;
11622 
11623   switch (Pred) {
11624   default:
11625     break;
11626 
11627   case ICmpInst::ICMP_SGE:
11628     std::swap(LHS, RHS);
11629     [[fallthrough]];
11630   case ICmpInst::ICMP_SLE:
11631     // (X + C1)<nsw> s<= (X + C2)<nsw> if C1 s<= C2.
11632     if (MatchBinaryAddToConst(LHS, RHS, C1, C2, SCEV::FlagNSW) && C1.sle(C2))
11633       return true;
11634 
11635     break;
11636 
11637   case ICmpInst::ICMP_SGT:
11638     std::swap(LHS, RHS);
11639     [[fallthrough]];
11640   case ICmpInst::ICMP_SLT:
11641     // (X + C1)<nsw> s< (X + C2)<nsw> if C1 s< C2.
11642     if (MatchBinaryAddToConst(LHS, RHS, C1, C2, SCEV::FlagNSW) && C1.slt(C2))
11643       return true;
11644 
11645     break;
11646 
11647   case ICmpInst::ICMP_UGE:
11648     std::swap(LHS, RHS);
11649     [[fallthrough]];
11650   case ICmpInst::ICMP_ULE:
11651     // (X + C1) u<= (X + C2)<nuw> for C1 u<= C2.
11652     if (MatchBinaryAddToConst(LHS, RHS, C1, C2, SCEV::FlagNUW) && C1.ule(C2))
11653       return true;
11654 
11655     break;
11656 
11657   case ICmpInst::ICMP_UGT:
11658     std::swap(LHS, RHS);
11659     [[fallthrough]];
11660   case ICmpInst::ICMP_ULT:
11661     // (X + C1) u< (X + C2)<nuw> if C1 u< C2.
11662     if (MatchBinaryAddToConst(LHS, RHS, C1, C2, SCEV::FlagNUW) && C1.ult(C2))
11663       return true;
11664     break;
11665   }
11666 
11667   return false;
