11670 bool ScalarEvolution::isKnownPredicateViaSplitting(CmpPredicate Pred,
11671                                                    const SCEV *LHS,
11672                                                    const SCEV *RHS) {
11673   if (Pred != ICmpInst::ICMP_ULT || ProvingSplitPredicate)
11674     return false;
11675 
11676   // Allowing arbitrary number of activations of isKnownPredicateViaSplitting on
11677   // the stack can result in exponential time complexity.
11678   SaveAndRestore Restore(ProvingSplitPredicate, true);
11679 
11680   // If L >= 0 then I `ult` L <=> I >= 0 && I `slt` L
11681   //
11682   // To prove L >= 0 we use isKnownNonNegative whereas to prove I >= 0 we use
11683   // isKnownPredicate.  isKnownPredicate is more powerful, but also more
11684   // expensive; and using isKnownNonNegative(RHS) is sufficient for most of the
11685   // interesting cases seen in practice.  We can consider "upgrading" L >= 0 to
11686   // use isKnownPredicate later if needed.
11687   return isKnownNonNegative(RHS) &&
11688          isKnownPredicate(CmpInst::ICMP_SGE, LHS, getZero(LHS->getType())) &&
11689          isKnownPredicate(CmpInst::ICMP_SLT, LHS, RHS);
11690 }
