11709 /// protected by a conditional between LHS and RHS.  This is used to
11710 /// to eliminate casts.
11711 bool ScalarEvolution::isLoopBackedgeGuardedByCond(const Loop *L,
11712                                                   CmpPredicate Pred,
11713                                                   const SCEV *LHS,
11714                                                   const SCEV *RHS) {
11715   // Interpret a null as meaning no loop, where there is obviously no guard
11716   // (interprocedural conditions notwithstanding). Do not bother about
11717   // unreachable loops.
11718   if (!L || !DT.isReachableFromEntry(L->getHeader()))
11719     return true;
