11708 /// isLoopBackedgeGuardedByCond - Test whether the backedge of the loop is
11709 /// protected by a conditional between LHS and RHS.  This is used to
11710 /// to eliminate casts.
11711 bool ScalarEvolution::isLoopBackedgeGuardedByCond(const Loop *L,
11712                                                   CmpPredicate Pred,
11713                                                   const SCEV *LHS,
11714                                                   const SCEV *RHS) {
11715   // Interpret a null as meaning no loop, where there is obviously no guard
11716   // (interprocedural conditions notwithstanding). Do not bother about
11717   // unreachable loops.
11718   if (!L || !DT.isReachableFromEntry(L->getHeader()))
11719     return true;
11720 
11721   if (VerifyIR)
11722     assert(!verifyFunction(*L->getHeader()->getParent(), &dbgs()) &&
11723            "This cannot be done on broken IR!");
11724 
11725 
11726   if (isKnownViaNonRecursiveReasoning(Pred, LHS, RHS))
11727     return true;
11728 
11729   BasicBlock *Latch = L->getLoopLatch();
11730   if (!Latch)
11731     return false;
11732 
11733   BranchInst *LoopContinuePredicate =
11734     dyn_cast<BranchInst>(Latch->getTerminator());
11735   if (LoopContinuePredicate && LoopContinuePredicate->isConditional() &&
11736       isImpliedCond(Pred, LHS, RHS,
11737                     LoopContinuePredicate->getCondition(),
11738                     LoopContinuePredicate->getSuccessor(0) != L->getHeader()))
11739     return true;
11740 
11741   // We don't want more than one activation of the following loops on the stack
11742   // -- that can lead to O(n!) time complexity.
11743   if (WalkingBEDominatingConds)
11744     return false;
11745 
11746   SaveAndRestore ClearOnExit(WalkingBEDominatingConds, true);
11747 
11748   // See if we can exploit a trip count to prove the predicate.
11749   const auto &BETakenInfo = getBackedgeTakenInfo(L);
11750   const SCEV *LatchBECount = BETakenInfo.getExact(Latch, this);
11751   if (LatchBECount != getCouldNotCompute()) {
11752     // We know that Latch branches back to the loop header exactly
11753     // LatchBECount times.  This means the backdege condition at Latch is
11754     // equivalent to  "{0,+,1} u< LatchBECount".
11755     Type *Ty = LatchBECount->getType();
11756     auto NoWrapFlags = SCEV::NoWrapFlags(SCEV::FlagNUW | SCEV::FlagNW);
11757     const SCEV *LoopCounter =
11758       getAddRecExpr(getZero(Ty), getOne(Ty), L, NoWrapFlags);
11759     if (isImpliedCond(Pred, LHS, RHS, ICmpInst::ICMP_ULT, LoopCounter,
11760                       LatchBECount))
11761       return true;
11762   }
11763 
11764   // Check conditions due to any @llvm.assume intrinsics.
11765   for (auto &AssumeVH : AC.assumptions()) {
11766     if (!AssumeVH)
11767       continue;
11768     auto *CI = cast<CallInst>(AssumeVH);
11769     if (!DT.dominates(CI, Latch->getTerminator()))
11770       continue;
11771 
11772     if (isImpliedCond(Pred, LHS, RHS, CI->getArgOperand(0), false))
11773       return true;
