11698   return any_of(*BB, [&](const Instruction &I) {
11699     using namespace llvm::PatternMatch;
11700 
11701     Value *Condition;
11702     return match(&I, m_Intrinsic<Intrinsic::experimental_guard>(
11703                          m_Value(Condition))) &&
11704            isImpliedCond(Pred, LHS, RHS, Condition, false);
